const items = $input.all();
const outputs = [];

for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  const keys = Object.keys(bin);

  if (!keys.length) {
    outputs.push({ json: { key: '', fileName: '', mimeType: '', url: '' } });
    continue;
  }

  for (const key of keys) {
    const meta = bin[key] || {};
    let url = '';
    try {
      const buf = await this.helpers.getBinaryDataBuffer(i, key);
      const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
      const base64 = Buffer.isBuffer(buf) ? buf.toString('base64') : Buffer.from(buf).toString('base64');
      url = base64 ? `data:${mime};base64,${base64}` : '';
    } catch (_) {
      const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
      const data = meta.data;
      if (typeof data === 'string' && data.length) url = `data:${mime};base64,${data}`;
    }

    outputs.push({
      json: {
        key,
        fileName: meta.fileName || meta.filename || key,
        mimeType: meta.mimeType || meta.mimetype || '',
        url
      }
    });
  }
}

return outputs.length ? outputs : [{ json: { key: '', fileName: '', mimeType: '', url: '' } }];

// ================================================
// n8n Code 节点专用代码
// 功能1：提取当前输入的文本描述（AI Agent 的 output）和 binary 图像
// 功能2：从 Code in JavaScript2 节点提取 binary 图像并合并
// 返回：包含描述 + 合并后的 binary 图像（当前输入 + JavaScript2）
// ================================================

// 调试信息：先打印当前输入的 binary 键名
console.log('Binary keys in current item:', Object.keys($input.item.binary || {}));
console.log('Binary count:', Object.keys($input.item.binary || {}).length);

// 1. 提取文本描述（从 AI Agent 的 output 字段）
const raw = $input.item.json.output || '';

let text = raw
  .replace(/^\s*<\|\s*begin_of_box\s*\|>\s*/i, '')
  .replace(/\s*<\|\s*end_of_box\s*\|>\s*$/i, '')
  .trim();

const pattern = /(\d+图\s*:\s*)([\s\S]*?)(?=\d+图\s*:|$)/g;
const descriptions = {};
let match;

while ((match = pattern.exec(text)) !== null) {
  const key = match[1].trim();          // 如 "1图:"
  let value = match[2].trim();
  value = value.replace(/\n+$/, '');    // 去尾部多余换行
  if (value) {
    descriptions[key] = value;
  }
}

// 2. 提取当前输入的所有 binary（使用 $input.item.binary）
const inputBinary = $input.item.binary || {};
const images = {};
let index = 0;

for (const originalKey in inputBinary) {
  if (inputBinary.hasOwnProperty(originalKey)) {
    const newKey = `${index + 1}图`;   // 重命名为 "1图"、"2图"...
    images[newKey] = { ...inputBinary[originalKey] };
    index++;
  }
}

// 3. 从 Code in JavaScript2 节点提取 binary 图像
let js2ImageCount = 0;
try {
  const js2Items = $('Code in JavaScript2').all();
  console.log('Code in JavaScript2 items count:', js2Items.length);

  if (js2Items && js2Items.length > 0) {
    js2Items.forEach((item, itemIdx) => {
      const js2Binary = item.binary || {};
      console.log(`JS2 item ${itemIdx} binary keys:`, Object.keys(js2Binary));

      for (const originalKey in js2Binary) {
        if (js2Binary.hasOwnProperty(originalKey) && originalKey.startsWith('image')) {
          // 继续编号：如果当前输入有2张图，JS2的图从 "3图" 开始
          const newKey = `${index + 1}图`;
          images[newKey] = { ...js2Binary[originalKey] };

          // 可选：添加来源标记
          images[newKey].sourceNode = 'Code in JavaScript2';
          images[newKey].sourceField = originalKey;
          images[newKey].sourceItemIndex = itemIdx;

          index++;
          js2ImageCount++;
        }
      }
    });
  }
} catch (err) {
  console.log('获取 Code in JavaScript2 失败:', err.message);
}

// 4. 输出一个 item，包含描述 + 合并后的 binary
return [{
  json: {
    descriptions: descriptions,          // { "1图": "...描述...", "2图": "..." }
    imageCount: index,                   // 总图像数（当前输入 + JS2）
    inputImageCount: Object.keys(inputBinary).length,  // 当前输入的图像数
    js2ImageCount: js2ImageCount,        // JS2 节点的图像数
    originalBinaryKeys: Object.keys(inputBinary),      // 调试用
    js2Connected: js2ImageCount > 0      // 是否成功获取 JS2 图像
  },
  binary: images                         // 合并后的 binary（"1图", "2图", "3图"...）
}];

// ================================================
// n8n Code 节点专用代码
// 功能：将 descriptions（1图、2图...）与 binary 图像一一对应，每个图形成一个 item
// 输入：上一个节点的 descriptions 和 binary 图像
// 输出：多个 item，每个 item 包含对应图的描述和 binary 数据
// ================================================

// 调试信息
console.log('Input binary keys:', Object.keys($input.item.binary || {}));
console.log('Input json:', JSON.stringify($input.item.json, null, 2));

const inputBinary = $input.item.binary || {};
const inputJson = $input.item.json || {};

// 获取 descriptions 对象（格式：{ "1图:": "描述1", "2图:": "描述2", ... }）
const descriptions = inputJson.descriptions || {};

// 获取所有 binary 图像，按名称排序（image0, image1, image2...）
const binaryKeys = Object.keys(inputBinary)
  .filter(key => key.startsWith('image'))
  .sort((a, b) => {
    // 按数字排序：image0, image1, image2...
    const numA = parseInt(a.replace('image', '')) || 0;
    const numB = parseInt(b.replace('image', '')) || 0;
    return numA - numB;
  });

console.log('Sorted binary keys:', binaryKeys);
console.log('Description keys:', Object.keys(descriptions));

// 生成对应数量的 items
const results = [];

// 遍历所有图像，为每个图像创建一个 item
binaryKeys.forEach((binaryKey, index) => {
  // 计算对应的 description key（"1图:", "2图:", ...）
  const descKey = `${index + 1}图:`;
  const description = descriptions[descKey] || descriptions[`${index + 1}图`] || '';

  // 构建单个 item
  const item = {
    json: {
      // 图的编号和信息
      imageNumber: index + 1,
      imageKey: binaryKey,
      description: description,
      descriptionKey: descKey,

      // 图像元数据
      fileName: inputBinary[binaryKey].fileName || '',
      mimeType: inputBinary[binaryKey].mimeType || '',
      fileExtension: inputBinary[binaryKey].fileExtension || '',
      fileSize: inputBinary[binaryKey].fileSize || '',

      // 原始完整数据（调试用，可删除）
      originalBinary: inputBinary[binaryKey]
    },

    // binary 数据：使用 "image" 作为标准键名（或保持原样）
    binary: {
      image: inputBinary[binaryKey]  // 统一用 "image" 键，方便后续节点使用
      // 或者保持原键名：[binaryKey]: inputBinary[binaryKey]
    }
  };

  results.push(item);
});

console.log(`Created ${results.length} items`);

// 如果没有图像，返回空提示
if (results.length === 0) {
  return [{
    json: {
      error: '未找到 binary 图像数据',
      availableKeys: Object.keys(inputBinary),
      descriptions: descriptions
    }
  }];
}

// 返回多个 item 的数组
return results;

// 输入：假设 AI Agent 输出在 $json.output 字段
const raw = $input.first().json.output || '';

// 清理首尾标记（<|begin_of_box|> 和 <|end_of_box|>）
let text = raw
  .replace(/^\s*<\|\s*begin_of_box\s*\|>\s*/i, '')
  .replace(/\s*<\|\s*end_of_box\s*\|>\s*$/i, '')
  .trim();

// 用正则匹配每个 “数字图:” 及其内容，直到下一个 “数字图:” 或结束
const pattern = /(\d+图\s*:\s*)([\s\S]*?)(?=\d+图\s*:|$)/g;

const result = {};
let match;

while ((match = pattern.exec(text)) !== null) {
  const key = match[1].trim();          // 如 "1图:"
  let value = match[2].trim();          // 后面的描述内容
  // 去掉可能的尾部多余换行
  value = value.replace(/\n+$/, '');

  if (value) {
    result[key] = value;
  }
}

// 返回单个 item，包含 { "1图": "...", "2图": "...", ... }
return [{ json: result }];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

// ================================================
// n8n Code 节点专用代码（直接复制粘贴即可执行）
// 功能1：遍历「Code in JavaScript8」节点的所有输出 items，提取 .json.output
// 功能2：从当前节点的输入（Aggregate 节点）提取二进制图像数据
// 返回 n8n 标准格式：对象数组（支持多 item，包含 binary 数据）
// ================================================

const toStr = (v) => (v == null ? '' : String(v).trim());

const getOutputFromNode = () => {
  try {
    // 获取当前节点的输入（Aggregate 节点输出）- 包含 binary 数据
    const inputItems = $input.all();
    const firstInputItem = inputItems && inputItems.length > 0 ? inputItems[0] : {};
    const inputBinary = firstInputItem.binary || {};

    // 提取 Aggregate 的图像元数据（用于放入 json）
    const aggregateImageMeta = [];
    const binaryKeys = Object.keys(inputBinary).filter(key => key.startsWith('image'));

    binaryKeys.forEach(key => {
      const img = inputBinary[key];
      aggregateImageMeta.push({
        fieldName: key,
        fileName: img.fileName || '',
        mimeType: img.mimeType || '',
        fileExtension: img.fileExtension || '',
        fileSize: img.fileSize || ''
      });
    });

    // 遍历上上上游节点「Code in JavaScript8」的所有输出 items
    const nodeItems = $('Code in JavaScript8').all();

    if (!nodeItems || nodeItems.length === 0) {
      // 即使没有 Code in JavaScript8 数据，也返回 Aggregate 的图像
      return [{
        json: {
          output: '',
          aggregateImages: aggregateImageMeta,
          note: 'Code in JavaScript8 无输出数据'
        },
        binary: inputBinary // 关键：保留 binary 数据
      }];
    }

    // 为每个 item 提取 output，并附加 Aggregate 的图像元数据和 binary 数据
    return nodeItems.map((item, index) => {
      const rawOutput = item.json?.output ?? item.json;

      return {
        json: {
          output: typeof rawOutput === 'string' 
            ? toStr(rawOutput) 
            : rawOutput,

          // Aggregate 图像元数据
          aggregateImages: aggregateImageMeta,
          aggregateImageCount: aggregateImageMeta.length,

          // 调试字段（确认后可删除）
          originalItemJson: item.json,
          sourceNode: 'Code in JavaScript8',
          itemIndex: index
        },

        // 关键：必须显式包含 binary 字段，n8n 才能在 Binary 标签页显示图像
        binary: inputBinary
      };
    });
  } catch (err) {
    console.log('执行失败:', err.message);
    return [{
      json: {
        output: '',
        aggregateImages: [],
        error: '执行错误',
        errorDetail: err.message
      }
    }];
  }
};

// 执行并返回 n8n 标准格式
return getOutputFromNode();

// ================================================
// n8n Code 节点专用代码
// 功能1：获取当前节点的输入数据（Aggregate 节点）
// 功能2：主动获取 Code in JavaScript2 节点的 binary 图像数据
// 返回：合并后的数据，包含 input 数据和 JavaScript2 的图像
// ================================================

const mergeInputAndImages = () => {
  try {
    // 1. 获取当前节点的输入（Aggregate 节点数据）
    const inputItems = $input.all();
    const firstInput = inputItems && inputItems.length > 0 ? inputItems[0] : {};
    const inputJson = firstInput.json || {};
    const inputBinary = firstInput.binary || {};

    // 2. 主动获取 Code in JavaScript2 节点的输出（包含 binary 图像）
    let js2Images = [];
    let js2Binary = {};

    try {
      const js2Items = $('Code in JavaScript2').all();

      if (js2Items && js2Items.length > 0) {
        // 遍历所有 items，收集 binary 图像
        js2Items.forEach((item, idx) => {
          const itemBinary = item.binary || {};

          // 提取所有 imageX 字段
          Object.keys(itemBinary).forEach(key => {
            if (key.startsWith('image') && itemBinary[key]) {
              const img = itemBinary[key];
              js2Images.push({
                fieldName: key,
                fileName: img.fileName || '',
                mimeType: img.mimeType || '',
                fileExtension: img.fileExtension || '',
                fileSize: img.fileSize || '',
                sourceItemIndex: idx
              });

              // 收集 binary 数据（避免字段名冲突，加上前缀）
              js2Binary[`js2_${key}_${idx}`] = itemBinary[key];
            }
          });
        });
      }
    } catch (js2Err) {
      console.log('获取 Code in JavaScript2 失败:', js2Err.message);
    }

    // 3. 返回合并后的数据
    return [{
      json: {
        // 当前输入的 JSON 数据
        inputData: inputJson,

        // Code in JavaScript2 的图像元数据
        js2Images: js2Images,
        js2ImageCount: js2Images.length,

        // 输入的 Aggregate 图像元数据
        aggregateImages: Object.keys(inputBinary).map(key => ({
          fieldName: key,
          fileName: inputBinary[key]?.fileName || '',
          mimeType: inputBinary[key]?.mimeType || ''
        })),

        // 调试信息
        inputItemCount: inputItems.length,
        source: 'merged_input_and_js2_images'
      },

      // 合并 binary 数据：输入的 + JavaScript2 的
      binary: {
        ...inputBinary,    // Aggregate 的图像
        ...js2Binary       // JavaScript2 的图像（带前缀避免冲突）
      }
    }];

  } catch (err) {
    console.log('合并数据失败:', err.message);
    return [{
      json: {
        error: '执行失败',
        errorDetail: err.message
      }
    }];
  }
};

// 执行并返回
return mergeInputAndImages();
